package com.ruoyi.web.controller.mes;
import com.ruoyi.common.core.controller.BaseController; import com.ruoyi.common.core.domain.AjaxResult; import com.ruoyi.common.core.page.TableDataInfo; import com.ruoyi.mes.purchase.domain.InventoryBalance; import com.ruoyi.mes.purchase.mapper.InventoryBalanceMapper; import jakarta.validation.Valid; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/mes/purchase/inventory") public class InventoryBalanceController extends BaseController { private final InventoryBalanceMapper mapper; public InventoryBalanceController(InventoryBalanceMapper mapper){this.mapper=mapper;} @PreAuthorize("@ss.hasPermi('mes:inventoryBalance:list')") @GetMapping("/list") public TableDataInfo list(InventoryBalance q){startPage();return getDataTable(mapper.selectList(q));} @PreAuthorize("@ss.hasPermi('mes:inventoryBalance:query')") @GetMapping("/{id}") public AjaxResult get(@PathVariable Long id){return success(mapper.selectById(id));} @PreAuthorize("@ss.hasPermi('mes:inventoryBalance:add')") @PostMapping public AjaxResult add(@Valid @RequestBody InventoryBalance o){o.setCreateBy(getUsername());return toAjax(mapper.insert(o));} @PreAuthorize("@ss.hasPermi('mes:inventoryBalance:edit')") @PutMapping public AjaxResult edit(@Valid @RequestBody InventoryBalance o){o.setUpdateBy(getUsername());return toAjax(mapper.update(o));} @PreAuthorize("@ss.hasPermi('mes:inventoryBalance:remove')") @DeleteMapping("/{ids}") public AjaxResult remove(@PathVariable Long[] ids){return toAjax(mapper.deleteByIds(ids));} }
